export function normalizeSpotScoreDisplay(value) {
        let score = parsePercentNumber(value);
        // Handle unexpected 10-point score inputs from external data.
        if (score > 0 && score <= 10) {
            score *= 10;
        }
        return formatPercentNumber(score);
    }

