export function parseDateDDMMYYYY(dateStr) {
    if (!dateStr || typeof dateStr !== 'string') return new Date(0);
    const parts = dateStr.split('.');
    if (parts.length !== 3) return new Date(0);
    const [day, month, year] = parts;
    const d = new Date(`${year}-${month}-${day}`);
    return isNaN(d.getTime()) ? new Date(0) : d;
}

export function calcPlIndex(score, preis) {
    // Use the extracted parseVal if available
    const pVal = typeof parseVal !== 'undefined' ? parseVal : (s) => parseFloat(String(s).replace(',', '.').replace('%', '').replace(' €', '')) || 0;
    const parsedScore = pVal(score);
    const parsedPreis = pVal(preis);
    if (parsedPreis === 0) return null;
    return parseFloat((parsedScore / parsedPreis).toFixed(2));
}

